&lt;h3 id=&#34;枚举端口&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#枚举端口&#34;&gt;#&lt;/a&gt; 枚举端口&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;Not shown: &lt;span class=&#34;token number&#34;&gt;989&lt;/span&gt; closed ports&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;PORT      STATE SERVICE&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;80&lt;/span&gt;/tcp    &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  http&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;135&lt;/span&gt;/tcp   &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  msrpc&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;139&lt;/span&gt;/tcp   &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  netbios-ssn&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;445&lt;/span&gt;/tcp   &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  microsoft-ds&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;3389&lt;/span&gt;/tcp  &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  ms-wbt-server&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;8080&lt;/span&gt;/tcp  &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  http-proxy&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;49152&lt;/span&gt;/tcp &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  unknown&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;49153&lt;/span&gt;/tcp &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  unknown&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;49154&lt;/span&gt;/tcp &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  unknown&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;49155&lt;/span&gt;/tcp &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  unknown&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;49156&lt;/span&gt;/tcp &lt;span class=&#34;token function&#34;&gt;open&lt;/span&gt;  unknown&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;开始前的小乐趣先个人&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#开始前的小乐趣先个人&#34;&gt;#&lt;/a&gt; 开始前的小乐趣先🐍个人&lt;/h3&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240426145608.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.githubusercontent.com/k1t0111/blog/main/image/20240426145853.png&#34; alt=&#34;image.png&#34; /&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;完美简单的 查找&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;详细枚举信息&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#详细枚举信息&#34;&gt;#&lt;/a&gt; 详细枚举信息&lt;/h3&gt;
